// Extract and validate input data
const body = $input.first().json.body;

if (!body.jobId || !body.bookId || !body.config) {
  throw new Error('Missing required fields: jobId, bookId, config');
}

// Normalize callback URL
let callbackUrl = body.callbackUrl || '';
if (!callbackUrl.startsWith('http')) {
  callbackUrl = 'https://' + callbackUrl;
}

// Preview mode: Only generate first chapter if true
const previewMode = body.config.previewMode === true;
const startFromChapter = body.config.startFromChapter || 1;

// Check for existing outline (for continuation after purchase)
const existingOutline = body.existingOutline || null;

// Multilingual support
const language = body.config.language || 'en';
const languageNames = {
  en: 'English', de: 'German (Deutsch)', es: 'Spanish (Español)',
  fr: 'French (Français)', it: 'Italian (Italiano)', pt: 'Portuguese (Português)',
  nl: 'Dutch (Nederlands)', pl: 'Polish (Polski)', ru: 'Russian (Русский)',
  ja: 'Japanese (日本語)', ko: 'Korean (한국어)', zh: 'Chinese (中文)',
  ar: 'Arabic (العربية)', tr: 'Turkish (Türkçe)', hi: 'Hindi (हिन्दी)',
  sv: 'Swedish (Svenska)', da: 'Danish (Dansk)', no: 'Norwegian (Norsk)',
  fi: 'Finnish (Suomi)', cs: 'Czech (Čeština)', el: 'Greek (Ελληνικά)',
  he: 'Hebrew (עברית)', id: 'Indonesian (Bahasa Indonesia)',
  th: 'Thai (ไทย)', vi: 'Vietnamese (Tiếng Việt)'
};
const languageName = languageNames[language] || 'English';

// Status messages by language
const messages = language === 'de' ? {
  creatingStructure: 'Erstelle Buchstruktur...',
  structureDone: 'Buchstruktur fertig - Starte Kapitel...',
  structureDonePreview: 'Buchstruktur fertig - Generiere Vorschau-Kapitel...',
  writingChapter: 'Kapitel {chapter}: {scene} wird geschrieben...',
  chapterOf: 'Kapitel {chapter}',
  chapterDone: 'Kapitel {chapter} fertig!',
  bookComplete: 'Dein Buch ist fertig!',
  previewComplete: 'Vorschau-Kapitel fertig! Kaufe das Buch für alle Kapitel.',
  generatingCover: 'Generiere Buchcover...',
  coverComplete: 'Buchcover erstellt!'
} : {
  creatingStructure: 'Creating book structure...',
  structureDone: 'Book structure ready - Starting chapters...',
  structureDonePreview: 'Book structure ready - Generating preview chapter...',
  writingChapter: 'Chapter {chapter}: Writing {scene}...',
  chapterOf: 'Chapter {chapter}',
  chapterDone: 'Chapter {chapter} complete!',
  bookComplete: 'Your book is ready!',
  previewComplete: 'Preview chapter complete! Purchase the book for all chapters.',
  generatingCover: 'Generating book cover...',
  coverComplete: 'Book cover created!'
};

// Supabase storage config for cover upload

const storageBucket = body.storageBucket || 'book-covers';

return [{
  json: {
    jobId: body.jobId,
    bookId: body.bookId,
    userId: body.userId,
    config: body.config,
    callbackUrl: callbackUrl,
    totalChapters: body.config.totalChapters || 5,
    webhookSecret:'Bookcraft2025vonBeyerdigital!1234321',
    // Preview mode settings
    previewMode: previewMode,
    startFromChapter: startFromChapter,
    // If preview mode, only generate chapter 1. Otherwise generate from startFromChapter.
    chaptersToGenerate: previewMode ? 1 : (body.config.totalChapters || 5),
    // Existing outline for continuation (skip GPT outline generation)
    existingOutline: existingOutline,
    isContinuation: !!existingOutline,
    // Language settings
    language: language,
    languageName: languageName,
    messages: messages,
    // Supabase storage for cover

    storageBucket: storageBucket
  }
}];

