const response = $input.first().json;
const setup = $('Setup').first().json;
const targetChapters = setup.totalChapters;

let outline;

// Check if we have an existing outline (continuation mode)
if (setup.existingOutline && setup.existingOutline.chapters) {
  console.log('Using existing outline for continuation');
  outline = setup.existingOutline;
} else {
  // Parse outline from GPT response
  try {
    const raw = response.choices?.[0]?.message?.content || '{}';
    outline = JSON.parse(raw);

    if (!outline.chapters || outline.chapters.length === 0) {
      throw new Error('No chapters');
    }

    // Ensure correct chapter count
    while (outline.chapters.length < targetChapters) {
      outline.chapters.push({
        number: outline.chapters.length + 1,
        title: `Kapitel ${outline.chapters.length + 1}`,
        summary: 'Fortsetzung',
        keyEvents: [
          { id: 1, title: 'Szene 1', description: 'Handlung', emotion: 'Spannend' },
          { id: 2, title: 'Szene 2', description: 'Entwicklung', emotion: 'Dramatisch' },
          { id: 3, title: 'Szene 3', description: 'Abschluss', emotion: 'Hoffnungsvoll' }
        ]
      });
    }

    outline.chapters = outline.chapters.slice(0, targetChapters);

    // Ensure 3 keyEvents minimum per chapter
    outline.chapters.forEach((ch, i) => {
      ch.number = i + 1;
      if (!ch.keyEvents || ch.keyEvents.length < 3) {
        ch.keyEvents = ch.keyEvents || [];
        while (ch.keyEvents.length < 3) {
          ch.keyEvents.push({
            id: ch.keyEvents.length + 1,
            title: `Szene ${ch.keyEvents.length + 1}`,
            description: 'Handlung',
            emotion: 'Spannend'
          });
        }
      }
      ch.keyEvents.forEach((ev, j) => { ev.id = j + 1; });
    });

  } catch (e) {
    // Fallback outline
    outline = {
      bookSummary: setup.config.title,
      chapters: Array.from({ length: targetChapters }, (_, i) => ({
        number: i + 1,
        title: `Kapitel ${i + 1}`,
        summary: `Kapitel ${i + 1}`,
        keyEvents: [
          { id: 1, title: 'Eröffnung', description: 'Start', emotion: 'Neugierig' },
          { id: 2, title: 'Entwicklung', description: 'Mitte', emotion: 'Spannend' },
          { id: 3, title: 'Höhepunkt', description: 'Ende', emotion: 'Dramatisch' }
        ]
      }))
    };
  }
}

// Filter chapters based on preview mode and startFromChapter
const startFrom = setup.startFromChapter || 1;
const chaptersToProcess = setup.previewMode 
  ? outline.chapters.filter(ch => ch.number === 1)  // Preview: only chapter 1
  : outline.chapters.filter(ch => ch.number >= startFrom);  // Full/Continue: from startFromChapter

// Count total scenes for progress calculation
const totalScenes = chaptersToProcess.reduce((sum, ch) => sum + ch.keyEvents.length, 0);

console.log('Chapters to process:', chaptersToProcess.length, 'Starting from:', startFrom, 'Preview mode:', setup.previewMode);

return [{
  json: {
    ...setup,
    outline: outline,  // Full outline (saved for later continuation)
    chaptersToProcess: chaptersToProcess,  // Only chapters to generate now
    totalScenes: totalScenes
  }
}];

// Flatten scenes only for chaptersToProcess (respects preview mode)
const data = $('Parse Outline').first().json;
const scenes = [];
let sceneIndex = 0;

// Use chaptersToProcess instead of full outline
for (const chapter of data.chaptersToProcess) {
  for (const event of chapter.keyEvents) {
    scenes.push({
      // Scene info
      sceneIndex: sceneIndex++,
      eventId: event.id,
      eventTitle: event.title,
      eventDescription: event.description,
      eventEmotion: event.emotion,
      // Chapter info
      chapterNumber: chapter.number,
      chapterTitle: chapter.title,
      chapterSummary: chapter.summary,
      totalEventsInChapter: chapter.keyEvents.length,
      // Global info (passed through)
      jobId: data.jobId,
      bookId: data.bookId,
      callbackUrl: data.callbackUrl,
      webhookSecret: data.webhookSecret,
      config: data.config,
      outline: data.outline,  // Full outline for reference
      totalChapters: data.totalChapters,
      totalScenes: data.totalScenes,
      previewMode: data.previewMode,
      chaptersToGenerate: data.chaptersToGenerate
    });
  }
}

return scenes.map(s => ({ json: s }));

