const response = $input.first().json;
const scene = $('Loop Scenes').first().json;

let text = '';
try {
  text = response.choices?.[0]?.message?.content || '';
} catch (e) {
  text = `[Szene: ${scene.eventTitle}]`;
}

// Clean up text
text = String(text)
  .replace(/^#+\s+.*$/gm, '')  // Remove headers
  .replace(/\*\*.*?\*\*/g, m => m.replace(/\*\*/g, ''))  // Remove bold
  .trim();

const wordCount = text.split(/\s+/).filter(Boolean).length;

return [{
  json: {
    // Scene content
    sceneText: text,
    wordCount: wordCount,
    // Pass through all scene data
    ...scene
  }
}];

// Check if this is the last scene in the chapter
const scene = $('Parse Scene').first().json;
const isLastSceneInChapter = scene.eventId === scene.totalEventsInChapter;

console.log('Check Chapter End:', { chapterNumber: scene.chapterNumber, eventId: scene.eventId, totalEventsInChapter: scene.totalEventsInChapter, isLastSceneInChapter });

// Pass through with flag
return [{
  json: {
    ...scene,
    isLastSceneInChapter: isLastSceneInChapter
  }
}];

// Supabase returns scenes as array of items
const scenes = $input.all().map(item => item.json);
const sceneData = $('Check Chapter End').first().json;

// Merge all scenes into chapter
let content = '';
let totalWords = 0;

if (scenes.length > 0) {
  // Sort by event_id to ensure correct order
  scenes.sort((a, b) => (a.event_id || 0) - (b.event_id || 0));
  content = scenes.map(s => s.content).join('\n\n');
  totalWords = scenes.reduce((sum, s) => sum + (s.word_count || 0), 0);
} else {
  // Fallback: use current scene
  content = sceneData.sceneText || '';
  totalWords = sceneData.wordCount || 0;
}

return [{
  json: {
    // Chapter data
    chapterNumber: sceneData.chapterNumber,
    chapterTitle: sceneData.chapterTitle,
    chapterContent: content,
    chapterWordCount: totalWords,
    scenesCount: scenes.length || 1,
    // Pass through globals
    jobId: sceneData.jobId,
    bookId: sceneData.bookId,
    callbackUrl: sceneData.callbackUrl,
    webhookSecret: sceneData.webhookSecret,
    totalChapters: sceneData.totalChapters,
    previewMode: sceneData.previewMode,
    outline: sceneData.outline
  }
}];

const book = $input.first().json;
const chapter = $('Merge Chapter').first().json;

let chapters = [];
try {
  chapters = JSON.parse(book.chapters_json || '[]');
} catch (e) {
  chapters = [];
}

// Add or update chapter
const idx = chapters.findIndex(c => c.number === chapter.chapterNumber);
const chData = {
  id: `chapter-${chapter.chapterNumber}`,
  number: chapter.chapterNumber,
  title: chapter.chapterTitle,
  content: chapter.chapterContent,
  wordCount: chapter.chapterWordCount
};

if (idx >= 0) {
  chapters[idx] = chData;
} else {
  chapters.push(chData);
}

chapters.sort((a, b) => a.number - b.number);

// Build full content
const fullContent = chapters
  .map(c => `# ${c.title}\n\n${c.content}`)
  .join('\n\n═══════════════════════════════════════\n\n');

return [{
  json: {
    bookId: chapter.bookId,
    chapters_json: JSON.stringify(chapters),
    content: fullContent
  }
}];

// Check if this is preview mode to determine final status
const setup = $('Setup').first().json;
const messages = setup.messages;

// Try to get outline from Parse Outline, fallback to existing outline from Setup
let outline;
try {
  const parseOutline = $('Parse Outline').first().json;
  outline = parseOutline.outline;
  console.log('Got outline from Parse Outline:', outline?.chapters?.length, 'chapters');
} catch (e) {
  console.log('Could not get outline from Parse Outline, trying Setup.existingOutline');
  outline = setup.existingOutline;
}

if (!outline || !outline.chapters) {
  console.error('No outline available! Setup:', JSON.stringify(setup));
  throw new Error('No outline available for creating chapter structures');
}

const isPreviewMode = setup.previewMode === true;

console.log('Determine Final Status - Preview mode:', isPreviewMode, 'Chapters in outline:', outline.chapters.length);

return [{
  json: {
    ...setup,
    outline: outline,
    finalStatus: isPreviewMode ? 'preview_completed' : 'completed',
    finalStep: isPreviewMode ? messages.previewComplete : messages.bookComplete,
    bookStatus: isPreviewMode ? 'preview' : 'completed'
  }
}];

// Create placeholder chapters for all chapters from outline
// Chapter 1 has content (already generated), chapters 2-N get placeholder
const book = $input.first().json;
const setup = $('Determine Final Status').first().json;
const outline = setup.outline;
const isPreviewMode = setup.previewMode === true;

console.log('Create All Chapter Structures - Book ID:', setup.bookId);
console.log('Outline chapters:', outline?.chapters?.length);
console.log('Existing chapters_json:', book.chapters_json?.substring(0, 200));

if (!outline || !outline.chapters || outline.chapters.length === 0) {
  console.error('No outline chapters available!');
  throw new Error('No outline chapters to create structures from');
}

// Parse existing chapters
let existingChapters = [];
try {
  existingChapters = JSON.parse(book.chapters_json || '[]');
  console.log('Parsed existing chapters:', existingChapters.length);
} catch (e) {
  console.log('Could not parse existing chapters, starting fresh');
  existingChapters = [];
}

// Create map of existing chapter content by number
const existingContent = new Map();
existingChapters.forEach(ch => {
  if (ch.number) existingContent.set(ch.number, ch);
});

console.log('Existing chapters with content:', existingContent.size);

// Build complete chapter list from outline
const allChapters = outline.chapters.map((outlineCh, idx) => {
  const chapterNum = outlineCh.number || (idx + 1);
  const existing = existingContent.get(chapterNum);

  if (existing && existing.content && existing.content.length > 100) {
    // Chapter has real content, use it
    console.log('Chapter', chapterNum, 'has content, keeping it');
    return existing;
  } else {
    // Create placeholder for locked chapters
    console.log('Chapter', chapterNum, 'is placeholder (locked:', isPreviewMode && chapterNum > 1, ')');
    return {
      id: `chapter-${chapterNum}`,
      number: chapterNum,
      title: outlineCh.title || `Kapitel ${chapterNum}`,
      content: '',  // Empty content - will be filled after purchase
      wordCount: 0,
      isLocked: isPreviewMode && chapterNum > 1,  // Mark as locked in preview mode
      summary: outlineCh.summary || ''  // Include summary for teaser
    };
  }
});

// Sort by chapter number
allChapters.sort((a, b) => a.number - b.number);

// Build content string (only from chapters with content)
const fullContent = allChapters
  .filter(c => c.content && c.content.length > 0)
  .map(c => `# ${c.title}\n\n${c.content}`)
  .join('\n\n═══════════════════════════════════════\n\n');

console.log('Final result:', allChapters.length, 'total chapters,', allChapters.filter(c => c.content).length, 'with content');

return [{
  json: {
    ...setup,
    bookId: setup.bookId,
    chapters_json: JSON.stringify(allChapters),
    content: fullContent,
    totalChaptersCreated: allChapters.length
  }
}];

// Prepare cover generation data from Parse Outline output
const data = $('Parse Outline').first().json;
const config = data.config;
const setup = $('Setup').first().json;
const language = setup.language || 'en';

// Genre-specific styling
const genreStyles = {
  'Fantasy': 'magical, mystical elements with enchanted atmosphere',
  'Science Fiction': 'futuristic, technological, space or sci-fi elements',
  'Mystery': 'dark, intriguing atmosphere with mysterious shadows',
  'Romance': 'romantic, elegant design with warm colors',
  'Thriller': 'suspenseful, dramatic with bold contrasts',
  'Horror': 'eerie, haunting atmosphere with dark tones',
  'Historical': 'vintage, period-appropriate styling',
  'Adventure': 'exciting, dynamic composition with action elements',
  'Biography': 'professional, dignified design',
  'Children': 'bright, playful, cheerful illustrations',
  'Young Adult': 'modern, trendy design appealing to teens',
  'Non-Fiction': 'clean, professional, informative design',
  'Märchen': 'fairy tale style, magical and whimsical',
  'Abenteuer': 'exciting adventure imagery',
  'Tiere': 'animal-focused, nature elements',
  'Familie': 'warm, family-oriented imagery'
};

const genreStyle = genreStyles[config.genre] || 'creative and eye-catching design';

// Build the cover generation prompt
const prompt = `Create a professional book cover design for a book titled "${config.title}".

CRITICAL REQUIREMENTS:
- Generate ONLY the front cover artwork as a FLAT, 2D image
- NO 3D book rendering, NO book spine, NO book edges, NO shadows suggesting a physical book
- NO back cover, NO wraparound design
- The entire image should be filled with the cover artwork edge-to-edge
- This is a flat rectangular image that will be printed as a book cover

Genre: ${config.genre}
Style: ${config.writingStyle || 'literary'}
Description: ${config.description || 'A captivating story'}
Target Audience: ${config.targetAudience || 'general readers'}

Visual Style Requirements:
- ${genreStyle}
- Include the book title "${config.title}" in elegant, readable typography
- Professional cover layout filling the entire image
- High-quality, print-ready artwork
- Color scheme appropriate for ${config.genre} genre
- Sophisticated, market-ready design

Output: A single flat cover image, NOT a 3D book mockup.`;

console.log('Cover Generation Setup:');
console.log('- Book:', config.title);
console.log('- Genre:', config.genre);
console.log('- Book ID:', data.bookId);

return [{
  json: {
    ...data,
    coverPrompt: prompt,
    supabaseUrl: setup.supabaseUrl,
    supabaseServiceKey: setup.supabaseServiceKey,
    storageBucket: setup.storageBucket,
    userId: data.userId
  }
}];

// Handle cover generation error
const response = $input.first().json;
const prepData = $('Prepare Cover Generation').first().json;

console.log('Cover generation failed:', JSON.stringify(response.error || response));

// Continue without cover - don't block book generation
return [{
  json: {
    ...prepData,
    coverUrl: null,
    coverError: response.error?.message || 'Cover generation failed'
  }
}];

// Parse OpenAI GPT-1.5 response (like Picture Book workflow)
const response = $input.first().json;
const prepData = $('Prepare Cover Generation').first().json;

let coverBase64 = '';
let coverTempUrl = '';

try {
  // OpenAI returns either b64_json or url
  if (response.data?.[0]?.b64_json) {
    coverBase64 = response.data[0].b64_json;
    console.log('✅ Got Base64 cover image from OpenAI');
